const body = $json.body ?? {};
const messageText = String(body.messageText ?? body.text ?? '').trim();
const normalized = messageText.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

function includesAny(values) {
  return values.some((value) => normalized.includes(value));
}

let intent = 'fallback';
let riskLevel = 'normal';
let needsClarification = false;
let replyText = 'Ainda nao entendi bem o que voce precisa. Me diga se voce quer ajuda com treino, substituicao de exercicio, execucao ou algum desconforto.';

if (normalized === '/start' || includesAny(['comecar', 'inicio', 'oi', 'ola'])) {
  intent = 'onboarding';
  needsClarification = true;
  replyText = 'Oi. Eu sou o Gym Buddy. Posso te ajudar com duvidas praticas de treino, substituicoes e conceitos basicos. Para comecar, voce quer montar um treino, ajustar um exercicio ou tirar uma duvida?';
} else if (includesAny(['dor', 'doendo', 'machuquei', 'lesao', 'lesao', 'desconforto', 'fisgada', 'joelho', 'ombro', 'lombar'])) {
  intent = 'discomfort';
  riskLevel = includesAny(['forte', 'aguda', 'fisgada', 'piorando', 'inchado', 'formigamento', 'peito', 'tontura']) ? 'stop' : 'caution';
  needsClarification = riskLevel !== 'stop';
  replyText = riskLevel === 'stop'
    ? 'Isso nao parece uma duvida comum de treino. Evite insistir no movimento agora e procure avaliacao de um profissional qualificado, especialmente se a dor for forte, aguda, estiver piorando ou vier com outros sintomas.'
    : 'Se ha desconforto, reduza ou pare o movimento que provoca o sintoma por enquanto. Onde voce sente isso e em qual exercicio acontece?';
} else if (includesAny(['trocar', 'substituir', 'substituicao', 'alternativa', 'no lugar de'])) {
  intent = 'substitution';
  needsClarification = true;
  replyText = 'Posso ajudar com uma substituicao. Qual exercicio voce quer trocar, por qual motivo e quais equipamentos voce tem disponiveis?';
} else if (includesAny(['treino', 'montar', 'divisao', 'serie', 'ficha'])) {
  intent = 'workout_request';
  needsClarification = true;
  replyText = 'Consigo te ajudar com uma estrutura geral de treino. Para nao fingir personalizacao, preciso saber: objetivo, dias por semana, equipamentos disponiveis, experiencia e se existe dor ou restricao.';
} else if (includesAny(['como fazer', 'execucao', 'tecnica', 'postura', 'movimento'])) {
  intent = 'exercise_question';
  needsClarification = true;
  replyText = 'Posso explicar a execucao em termos gerais. Qual exercicio voce quer entender melhor?';
} else if (includesAny(['falha', 'rir'])) {
  intent = 'concept_explanation';
  replyText = 'Treinar perto da falha significa terminar a serie com poucas repeticoes em reserva. Exemplo: RIR 2 quer dizer que voce provavelmente conseguiria fazer mais 2 repeticoes com boa tecnica. A ideia e desafiar o musculo sem transformar toda serie em perda de tecnica.';
} else if (includesAny(['volume', 'intensidade', 'frequencia', 'descanso', 'progressao', 'hipertrofia'])) {
  intent = 'concept_explanation';
  replyText = 'Em termos simples: hipertrofia depende de consistencia, volume suficiente, series desafiadoras, progressao e recuperacao. Se quiser, eu explico esse conceito com um exemplo pratico.';
}

return [
  {
    json: {
      replyText,
      intent,
      riskLevel,
      needsClarification,
      shouldPersist: false,
      input: {
        channel: body.channel ?? 'local-smoke',
        chatId: body.chatId ?? null,
        messageText,
        messageType: body.messageType ?? 'text',
        receivedAt: body.receivedAt ?? new Date().toISOString()
      }
    }
  }
];
